struct half2 {
  float x, y;
};
static inline half2 operator+(const half2& a, const half2& b) {
  return half2{a.x + b.x, a.y + b.y};
}
static inline half2 operator*(const half2& a, const half2& b) {
  return half2{a.x * b.x, a.y * b.y};
}
static inline bool operator==(const half2& a, const half2& b) {
  return a.x == b.x && a.y == b.y;
}

template <int N, class F>
double benchmark(F&& f) {
  double sum = 0.0;
  for (int i = 0; i < N; i++) sum += f();
  return sum / (double)N;
}

char* ReadFile(const char* filename) {
  char* buffer = NULL;
  int file_size, read_size;
  FILE* file = fopen(filename, "r");
  if (!file) return NULL;

  fseek(file, 0, SEEK_END);
  file_size = (int)ftell(file);
  rewind(file);
  buffer = (char*)malloc(sizeof(char) * (file_size + 1));
  read_size = (int)fread(buffer, sizeof(char), file_size, file);
  fclose(file);
  buffer[file_size] = '\0';
  if (read_size != file_size) {
    free(buffer);
    buffer = NULL;
  }
  return buffer;
}

void flushed_printf(const char* format, ...) {
  va_list args;
  va_start(args, format);
  vprintf(format, args);
  va_end(args);
  fflush(stdout);
}

void show_progress_init(int length) {
  flushed_printf("[");
  for (int i = 0; length > i; i++) flushed_printf(" ");
  flushed_printf("]");
  for (int i = 0; length >= i; i++) flushed_printf("\b");
}

void show_progress_step(int domove, char newchar) {
  flushed_printf("%c", newchar);
  if (!domove) flushed_printf("\b");
}

void show_progress_done(void) { flushed_printf("\n"); }

bool argument_parsing(int argc, char* argv[], ArgParams* output) {
  int arg_count = 0;
  for (int i = 1; argc > i; i++) {
    if ((strcmp(argv[i], "-h") == 0) || (strcmp(argv[i], "--help") == 0)) {
      return false;
    } else if ((strcmp(argv[i], "-w") == 0) ||
               (strcmp(argv[i], "--workgroup-stride") == 0)) {
      output->block_strided = true;
    } else if ((strcmp(argv[i], "-H") == 0) ||
               (strcmp(argv[i], "--host-alloc") == 0)) {
      output->host_allocated = true;
    } else if ((strcmp(argv[i], "-t") == 0) ||
               (strcmp(argv[i], "--use-os-timer") == 0)) {
      output->use_os_timer = true;
    } else {
      unsigned long value = strtoul(argv[i], NULL, 10);
      switch (arg_count) {
        case 0:
          output->device_index = (int)value;
          arg_count++;
          break;
        case 1:
          output->wg_size = (int)value;
          arg_count++;
          break;
        case 2:
          output->vecwidth = (unsigned int)value;
          arg_count++;
          break;
        case 3:
          output->elements_per_wi = (unsigned int)value;
          arg_count++;
          break;
        case 4:
          output->fusion_degree = (unsigned int)value;
          arg_count++;
          break;
        default:
          return false;
      }
    }
  }
  return true;
}

