#define TOL      (0.001)
#define STR_SIZE (256)
#define MAX_PD   (3.0e6)

#define PRECISION    0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI         100

#define FACTOR_CHIP  0.5

#define WG_SIZE_X (64)
#define WG_SIZE_Y (4)

float t_chip      = 0.0005f;
float chip_height = 0.016f;
float chip_width  = 0.016f;
float amb_temp    = 80.0f;

static inline void tvsub(struct timeval *x, struct timeval *y, struct timeval *ret)
{
    ret->tv_sec = x->tv_sec - y->tv_sec;
    ret->tv_usec = x->tv_usec - y->tv_usec;
    if (ret->tv_usec < 0) {
        ret->tv_usec += 1000000;
        ret->tv_sec--;
    }
}

void fatal(char *s)
{
