static inline void process_block(int* reference_d, int* input_itemsets_d, int cols, int penalty, int base, int b_index_x, int b_index_y) {
    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    auto SCORE = [&](int i, int j) -> int& { return input_itemsets_l[j + i * (BLOCK_SIZE + 1)]; };
    auto REF   = [&](int i, int j) -> int& { return reference_l[j + i * BLOCK_SIZE]; };

    int block_origin = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;
    int index_nw = block_origin;
    int index_w = block_origin + cols;
    int index_n = block_origin + 1;
    int index = block_origin + cols + 1;

    SCORE(0, 0) = input_itemsets_d[index_nw];

    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
        for (int ty = 0; ty < BLOCK_SIZE; ty++) {
            REF(ty, tx) = reference_d[index + tx + cols * ty];
        }
    }

    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
        SCORE(tx + 1, 0) = input_itemsets_d[index_w + cols * tx];
    }

    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
        SCORE(0, tx + 1) = input_itemsets_d[index_n + tx];
    }

    for (int m = 0; m < BLOCK_SIZE; m++) {
        for (int tx = 0; tx <= m; tx++) {
            int t_index_x = tx + 1;
            int t_index_y = m - tx + 1;
            SCORE(t_index_y, t_index_x) =
                maximum(SCORE(t_index_y - 1, t_index_x - 1) + REF(t_index_y - 1, t_index_x - 1),
                        SCORE(t_index_y, t_index_x - 1) - penalty,
                        SCORE(t_index_y - 1, t_index_x) - penalty);
        }
    }

    for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
        for (int tx = 0; tx <= m; tx++) {
            int t_index_x = tx + BLOCK_SIZE - m;
            int t_index_y = BLOCK_SIZE - tx;
            SCORE(t_index_y, t_index_x) =
                maximum(SCORE(t_index_y - 1, t_index_x - 1) + REF(t_index_y - 1, t_index_x - 1),
                        SCORE(t_index_y, t_index_x - 1) - penalty,
                        SCORE(t_index_y - 1, t_index_x) - penalty);
        }
    }

    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
        for (int ty = 0; ty < BLOCK_SIZE; ty++) {
            input_itemsets_d[index + tx + cols * ty] = SCORE(ty + 1, tx + 1);
        }
    }
}

static void nw_kernel1_omp(int* reference_d, int* input_itemsets_d, int cols, int penalty, int blk, int block_width, int worksize, int offset_r, int offset_c) {
    (void)block_width;
    (void)worksize;
    int base = offset_r * cols + offset_c;
    #pragma omp parallel for schedule(static)
    for (int bx = 0; bx < blk; bx++) {
        int b_index_x = bx;
        int b_index_y = blk - 1 - bx;
        process_block(reference_d, input_itemsets_d, cols, penalty, base, b_index_x, b_index_y);
    }
}

static void nw_kernel2_omp(int* reference_d, int* input_itemsets_d, int cols, int penalty, int blk, int block_width, int worksize, int offset_r, int offset_c) {
    (void)worksize;
    int base = offset_r * cols + offset_c;
    #pragma omp parallel for schedule(static)
    for (int bx = 0; bx < blk; bx++) {
        int b_index_x = bx + block_width - blk;
        int b_index_y = block_width - bx - 1;
        process_block(reference_d, input_itemsets_d, cols, penalty, base, b_index_x, b_index_y);
    }
}

int main(int argc, char **argv) {
    printf("WG size of kernel = %d \n", BLOCK_SIZE);

    int max_rows, max_cols, penalty;
    char *tempchar;

    if (argc >= 4) {
        max_rows = atoi(argv[1]);
        max_cols = atoi(argv[1]);
        penalty = atoi(argv[2]);
        tempchar = argv[3];

        int cur_arg;
        for (cur_arg = 1; cur_arg < argc; cur_arg++) {
            if (strcmp(argv[cur_arg], "-p") == 0) {
                if (argc >= cur_arg + 1) {
                    platform_id_inuse = atoi(argv[cur_arg + 1]);
                    cur_arg++;
                }
            } else if (strcmp(argv[cur_arg], "-d") == 0) {
                if (argc >= cur_arg + 1) {
                    device_id_inuse = atoi(argv[cur_arg + 1]);
                    cur_arg++;
                }
            }
        }
    } else {
        usage(argc, argv);
    }

    if (atoi(argv[1]) % 16 != 0) {
        fprintf(stderr, "The dimension values must be a multiple of 16\n");
        exit(1);
    }

    max_rows = max_rows + 1;
    max_cols = max_cols + 1;

    int *reference;
    int *input_itemsets;
    int *output_itemsets;

    reference = (int *)malloc(max_rows * max_cols * sizeof(int));
    input_itemsets = (int *)malloc(max_rows * max_cols * sizeof(int));
    output_itemsets = (int *)malloc(max_rows * max_cols * sizeof(int));

    srand(7);

    for (int i = 0; i < max_cols; i++) {
        for (int j = 0; j < max_rows; j++) {
            input_itemsets[i * max_cols + j] = 0;
        }
    }

    for (int i = 1; i < max_rows; i++) {
        input_itemsets[i * max_cols] = rand() % 10 + 1;
    }

    for (int j = 1; j < max_cols; j++) {
        input_itemsets[j] = rand() % 10 + 1;
    }

    for (int i = 1; i < max_cols; i++) {
        for (int j = 1; j < max_rows; j++) {
            reference[i * max_cols + j] = blosum62[input_itemsets[i * max_cols]][input_itemsets[j]];
        }
    }

    for (int i = 1; i < max_rows; i++)
        input_itemsets[i * max_cols] = -i * penalty;
    for (int j = 1; j < max_cols; j++)
        input_itemsets[j] = -j * penalty;

    int sourcesize = 1024 * 1024;
    char *source = (char *)calloc(sourcesize, sizeof(char));
    if (!source) {
        printf("ERROR: calloc(%d) failed\n", sourcesize);
        return -1;
    }

    FILE *fp = fopen(tempchar, "rb");
    if (!fp) {
        printf("ERROR: unable to open '%s'\n", tempchar);
        free(source);
        return -1;
    }
    fread(source + strlen(source), sourcesize, 1, fp);
    fclose(fp);

    int worksize = max_cols - 1;
    printf("worksize = %d\n", worksize);

    int offset_r = 0, offset_c = 0;
    int block_width = worksize / BLOCK_SIZE;

    printf("Processing upper-left matrix\n");
    for (int blk = 1; blk <= worksize / BLOCK_SIZE; blk++) {
        nw_kernel1_omp(reference, input_itemsets, max_cols, penalty, blk, block_width, worksize, offset_r, offset_c);
    }

    printf("Processing lower-right matrix\n");
    for (int blk = worksize / BLOCK_SIZE - 1; blk >= 1; blk--) {
        nw_kernel2_omp(reference, input_itemsets, max_cols, penalty, blk, block_width, worksize, offset_r, offset_c);
    }

    memcpy(output_itemsets, input_itemsets, max_cols * max_rows * sizeof(int));

#ifdef TRACEBACK
    FILE *fpo = fopen("result.txt", "w");
    fprintf(fpo, "print traceback value GPU:\n");

    for (int i = max_rows - 2, j = max_rows - 2; i >= 0, j >= 0;) {
        int nw, n, w, traceback;
        if (i == max_rows - 2 && j == max_rows - 2)
            fprintf(fpo, "%d ", output_itemsets[i * max_cols + j]);
        if (i == 0 && j == 0)
            break;
        if (i > 0 && j > 0) {
            nw = output_itemsets[(i - 1) * max_cols + j - 1];
            w = output_itemsets[i * max_cols + j - 1];
            n = output_itemsets[(i - 1) * max_cols + j];
        } else if (i == 0) {
            nw = n = LIMIT;
            w = output_itemsets[i * max_cols + j - 1];
        } else if (j == 0) {
            nw = w = LIMIT;
            n = output_itemsets[(i - 1) * max_cols + j];
        } else {
        }

        int new_nw, new_w, new_n;
        new_nw = nw + reference[i * max_cols + j];
        new_w = w - penalty;
        new_n = n - penalty;

        traceback = maximum(new_nw, new_w, new_n);
        if (traceback == new_nw)
            traceback = nw;
        if (traceback == new_w)
            traceback = w;
        if (traceback == new_n)
            traceback = n;

        fprintf(fpo, "%d ", traceback);

        if (traceback == nw) { i--; j--; continue; }
        else if (traceback == w) { j--; continue; }
        else if (traceback == n) { i--; continue; }
        else;
    }

    fclose(fpo);
#endif

    printf("Computation Done\n");

    free(source);
    free(reference);
    free(input_itemsets);
    free(output_itemsets);

    return 0;
}

