static inline void nw_kernel1_omp(int *reference_d, int *input_itemsets_d, int *output_itemsets_d,
                                  int cols, int penalty, int blk, int block_width, int worksize,
                                  int offset_r, int offset_c) {
    (void)output_itemsets_d;
    (void)block_width;
    (void)worksize;

    int base = offset_r * cols + offset_c;

#pragma omp parallel for schedule(static)
    for (int bx = 0; bx < blk; bx++) {
        int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
        int reference_l[BLOCK_SIZE * BLOCK_SIZE];

#define SCORE(i, j) input_itemsets_l[(j) + (i) * (BLOCK_SIZE + 1)]
#define REF(i, j) reference_l[(j) + (i) * BLOCK_SIZE]

        int b_index_x = bx;
        int b_index_y = blk - 1 - bx;
        int index_nw = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

        SCORE(0, 0) = input_itemsets_d[index_nw];

        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                REF(ty, tx) = reference_d[index_nw + (ty + 1) * cols + (tx + 1)];
            }
        }

        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            SCORE(tx + 1, 0) = input_itemsets_d[index_nw + (tx + 1) * cols];
        }

        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            SCORE(0, tx + 1) = input_itemsets_d[index_nw + tx + 1];
        }

        for (int m = 0; m < BLOCK_SIZE; m++) {
            for (int tx = 0; tx <= m; tx++) {
                int t_index_x = tx + 1;
                int t_index_y = m - tx + 1;
                SCORE(t_index_y, t_index_x) =
                    maximum(SCORE((t_index_y - 1), (t_index_x - 1)) + REF((t_index_y - 1), (t_index_x - 1)),
                            SCORE((t_index_y), (t_index_x - 1)) - (penalty),
                            SCORE((t_index_y - 1), (t_index_x)) - (penalty));
            }
        }

        for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
            for (int tx = 0; tx <= m; tx++) {
                int t_index_x = tx + BLOCK_SIZE - m;
                int t_index_y = BLOCK_SIZE - tx;
                SCORE(t_index_y, t_index_x) =
                    maximum(SCORE((t_index_y - 1), (t_index_x - 1)) + REF((t_index_y - 1), (t_index_x - 1)),
                            SCORE((t_index_y), (t_index_x - 1)) - (penalty),
                            SCORE((t_index_y - 1), (t_index_x)) - (penalty));
            }
        }

        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                input_itemsets_d[index_nw + (ty + 1) * cols + (tx + 1)] = SCORE((ty + 1), (tx + 1));
            }
        }

#undef SCORE
#undef REF
    }
}

