static inline void compute_block(
    int *reference_d,
    int *input_itemsets_d,
    int cols,
    int penalty,
    int offset_r,
    int offset_c,
    int b_index_x,
    int b_index_y)
{
    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    #define SCORE(i, j) input_itemsets_l[(j) + (i) * (BLOCK_SIZE + 1)]
    #define REF(i, j)   reference_l[(j) + (i) * BLOCK_SIZE]

    int base = offset_r * cols + offset_c;
    int tile_base = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

    SCORE(0, 0) = input_itemsets_d[tile_base];

    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            REF(ty, tx) = reference_d[tile_base + (cols + 1) + tx + cols * ty];
        }
    }

    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
        SCORE(tx + 1, 0) = input_itemsets_d[tile_base + cols + cols * tx];
    }

    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
        SCORE(0, tx + 1) = input_itemsets_d[tile_base + 1 + tx];
    }

    for (int m = 0; m < BLOCK_SIZE; m++) {
        for (int tx = 0; tx <= m; tx++) {
            int t_index_x = tx + 1;
            int t_index_y = m - tx + 1;
            SCORE(t_index_y, t_index_x) = maximum(
                SCORE(t_index_y - 1, t_index_x - 1) + REF(t_index_y - 1, t_index_x - 1),
                SCORE(t_index_y, t_index_x - 1) - penalty,
                SCORE(t_index_y - 1, t_index_x) - penalty
            );
        }
    }

    for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
        for (int tx = 0; tx <= m; tx++) {
            int t_index_x = tx + BLOCK_SIZE - m;
            int t_index_y = BLOCK_SIZE - tx;
            SCORE(t_index_y, t_index_x) = maximum(
                SCORE(t_index_y - 1, t_index_x - 1) + REF(t_index_y - 1, t_index_x - 1),
                SCORE(t_index_y, t_index_x - 1) - penalty,
                SCORE(t_index_y - 1, t_index_x) - penalty
            );
        }
    }

    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            input_itemsets_d[tile_base + (cols + 1) + tx + cols * ty] = SCORE(ty + 1, tx + 1);
        }
    }

    #undef SCORE
    #undef REF
}

void nw_kernel1_omp(
    int *reference_d,
    int *input_itemsets_d,
    int *output_itemsets_d,
    int cols,
    int penalty,
    int blk,
    int block_width,
    int worksize,
    int offset_r,
    int offset_c)
{
    (void)output_itemsets_d;
    (void)block_width;
    (void)worksize;

    #pragma omp parallel for schedule(static)
    for (int bx = 0; bx < blk; bx++) {
        int b_index_x = bx;
        int b_index_y = blk - 1 - bx;
        compute_block(reference_d, input_itemsets_d, cols, penalty, offset_r, offset_c, b_index_x, b_index_y);
    }
}

void nw_kernel2_omp(
    int *reference_d,
    int *input_itemsets_d,
    int *output_itemsets_d,
    int cols,
    int penalty,
    int blk,
    int block_width,
    int worksize,
    int offset_r,
    int offset_c)
{
    (void)output_itemsets_d;
    (void)worksize;

    #pragma omp parallel for schedule(static)
    for (int bx = 0; bx < blk; bx++) {
        int b_index_x = bx + block_width - blk;
        int b_index_y = block_width - bx - 1;
        compute_block(reference_d, input_itemsets_d, cols, penalty, offset_r, offset_c, b_index_x, b_index_y);
    }
}

