static inline void process_tile(int *reference_d, int *input_itemsets_d, int cols, int penalty, int b_index_x, int b_index_y, int base) {
    int score[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int ref[BLOCK_SIZE * BLOCK_SIZE];

#define SCORE(i, j) score[(j) + (i) * (BLOCK_SIZE + 1)]
#define REF(i, j) ref[(j) + (i) * BLOCK_SIZE]

    int nw = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

    SCORE(0, 0) = input_itemsets_d[nw];

    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            REF(ty, tx) = reference_d[nw + (ty + 1) * cols + (tx + 1)];
        }
    }

    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
        SCORE(tx + 1, 0) = input_itemsets_d[nw + cols * (tx + 1)];
    }

    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
        SCORE(0, tx + 1) = input_itemsets_d[nw + (tx + 1)];
    }

    for (int m = 0; m < BLOCK_SIZE; m++) {
        for (int tx = 0; tx <= m; tx++) {
            int t_index_x = tx + 1;
            int t_index_y = m - tx + 1;
            SCORE(t_index_y, t_index_x) =
                maximum(SCORE((t_index_y - 1), (t_index_x - 1)) + REF((t_index_y - 1), (t_index_x - 1)),
                        SCORE((t_index_y), (t_index_x - 1)) - (penalty),
                        SCORE((t_index_y - 1), (t_index_x)) - (penalty));
        }
    }

    for (int m = BLOCK_SIZE - 2; 0 <= m; m--) {
        for (int tx = 0; tx <= m; tx++) {
            int t_index_x = tx + BLOCK_SIZE - m;
            int t_index_y = BLOCK_SIZE - tx;
            SCORE(t_index_y, t_index_x) =
                maximum(SCORE((t_index_y - 1), (t_index_x - 1)) + REF((t_index_y - 1), (t_index_x - 1)),
                        SCORE((t_index_y), (t_index_x - 1)) - (penalty),
                        SCORE((t_index_y - 1), (t_index_x)) - (penalty));
        }
    }

    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            input_itemsets_d[nw + (ty + 1) * cols + (tx + 1)] = SCORE((ty + 1), (tx + 1));
        }
    }

#undef SCORE
#undef REF
}

