    fclose(fid);

    free(disk);
    free(objxy);
    free(weights);
    free(likelihood);
    free(arrayX);
    free(arrayY);
    free(xj);
    free(yj);
    free(CDF);
    free(ind);
    free(u);
    free(partial_sums);

    (void)kernel_start_all;
    return 0;
}

