#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <cmath>
#include <omp.h>

#define fp float

#ifdef RD_WG_SIZE_0_0
#define NUMBER_THREADS RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define NUMBER_THREADS RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define NUMBER_THREADS RD_WG_SIZE
#else
#define NUMBER_THREADS 256
#endif

int platform_id_inuse = 0;
int device_id_inuse = 0;

static void write_graphics(char* filename, fp* input, int data_rows, int data_cols, int major, int data_range) {
    FILE* fid;
    int i, j;

    fid = fopen(filename, "w");
    if (fid == NULL) {
        printf("The file was not created/opened for writing\n");
        return;
    }

    fprintf(fid, "P2\n");
    fprintf(fid, "%d %d\n", data_cols, data_rows);
    fprintf(fid, "%d\n", data_range);

    if (major == 0) {
        for (i = 0; i < data_rows; i++) {
            for (j = 0; j < data_cols; j++) {
                fprintf(fid, "%d ", (int)input[i * data_cols + j]);
            }
            fprintf(fid, "\n");
        }
    } else {
        for (i = 0; i < data_rows; i++) {
            for (j = 0; j < data_cols; j++) {
                fprintf(fid, "%d ", (int)input[j * data_rows + i]);
            }
            fprintf(fid, "\n");
        }
    }

    fclose(fid);
}

static void read_graphics(char* filename, fp* input, int data_rows, int data_cols, int major) {
    FILE* fid;
    int i, j;
    char c;
    int temp;

    fid = fopen(filename, "r");
    if (fid == NULL) {
        printf("The file was not opened for reading\n");
        return;
    }

    i = 0;
    while (i < 3) {
        c = fgetc(fid);
        if (c == '\n') {
            i = i + 1;
        }
    }

    if (major == 0) {
        for (i = 0; i < data_rows; i++) {
            for (j = 0; j < data_cols; j++) {
                fscanf(fid, "%d", &temp);
                input[i * data_cols + j] = (fp)temp;
            }
        }
    } else {
        for (i = 0; i < data_rows; i++) {
            for (j = 0; j < data_cols; j++) {
                fscanf(fid, "%d", &temp);
                input[j * data_rows + i] = (fp)temp;
            }
        }
    }

    fclose(fid);
}

static void resize_image(fp* input, int input_rows, int input_cols, fp* output, int output_rows, int output_cols, int major) {
    int i, j;
    int i2, j2;

    if (major == 0) {
        for (i = 0, i2 = 0; i < output_rows; i++, i2++) {
            if (i2 >= input_rows) {
                i2 = i2 - input_rows;
            }
            for (j = 0, j2 = 0; j < output_cols; j++, j2++) {
                if (j2 >= input_cols) {
                    j2 = j2 - input_cols;
                }
                output[i * output_cols + j] = input[i2 * input_cols + j2];
            }
        }
    } else {
        for (j = 0, j2 = 0; j < output_cols; j++, j2++) {
            if (j2 >= input_cols) {
                j2 = j2 - input_cols;
            }
            for (i = 0, i2 = 0; i < output_rows; i++, i2++) {
                if (i2 >= input_rows) {
                    i2 = i2 - input_rows;
                }
                output[j * output_rows + i] = input[j2 * input_rows + i2];
            }
        }
    }
}

static void extract_kernel(long d_Ne, fp* d_I) {
    #pragma omp parallel for schedule(static)
    for (long ei = 0; ei < d_Ne; ei++) {
        d_I[ei] = expf(d_I[ei] / 255.0f);
    }
}

static void prepare_kernel(long d_Ne, fp* d_I, fp* d_sums, fp* d_sums2) {
    #pragma omp parallel for schedule(static)
    for (long ei = 0; ei < d_Ne; ei++) {
        d_sums[ei] = d_I[ei];
        d_sums2[ei] = d_I[ei] * d_I[ei];
    }
}

static void reduce_kernel(long d_Ne, long d_no, int d_mul, fp* d_sums, fp* d_sums2, int gridDim) {
    (void)d_Ne;
    int nf = NUMBER_THREADS - (gridDim * NUMBER_THREADS - (int)d_no);

    #pragma omp parallel for schedule(static)
    for (int bx = 0; bx < gridDim; bx++) {
        fp d_psum[NUMBER_THREADS];
        fp d_psum2[NUMBER_THREADS];
        int i, tx;
        int df = 0;

        for (tx = 0; tx < NUMBER_THREADS; tx++) {
            int ei = (bx * NUMBER_THREADS) + tx;
            if (ei < d_no) {
                d_psum[tx] = d_sums[(long)ei * d_mul];
                d_psum2[tx] = d_sums2[(long)ei * d_mul];
            } else {
                d_psum[tx] = 0.0f;
                d_psum2[tx] = 0.0f;
            }
        }

        if (nf == NUMBER_THREADS) {
            for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                for (tx = NUMBER_THREADS - 1; tx >= 0; tx--) {
                    if (((tx + 1) % i) == 0) {
                        d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                        d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                    }
                }
            }
            d_sums[(long)bx * d_mul * NUMBER_THREADS] = d_psum[NUMBER_THREADS - 1];
            d_sums2[(long)bx * d_mul * NUMBER_THREADS] = d_psum2[NUMBER_THREADS - 1];
        } else {
            if (bx != (gridDim - 1)) {
                for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                    for (tx = NUMBER_THREADS - 1; tx >= 0; tx--) {
                        if (((tx + 1) % i) == 0) {
                            d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                            d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                        }
                    }
                }
                d_sums[(long)bx * d_mul * NUMBER_THREADS] = d_psum[NUMBER_THREADS - 1];
                d_sums2[(long)bx * d_mul * NUMBER_THREADS] = d_psum2[NUMBER_THREADS - 1];
            } else {
                for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                    if (nf >= i) {
                        df = i;
                    }
                }

                for (i = 2; i <= df; i = 2 * i) {
                    for (tx = df - 1; tx >= 0; tx--) {
                        if (((tx + 1) % i) == 0 && tx < df) {
                            d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                            d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                        }
                    }
                }

                int t = df - 1;
                for (i = (bx * NUMBER_THREADS) + df; i < (bx * NUMBER_THREADS) + nf; i++) {
                    d_psum[t] = d_psum[t] + d_sums[i];
                    d_psum2[t] = d_psum2[t] + d_sums2[i];
                }

                d_sums[(long)bx * d_mul * NUMBER_THREADS] = d_psum[t];
                d_sums2[(long)bx * d_mul * NUMBER_THREADS] = d_psum2[t];
            }
        }
    }
}

static void srad_kernel(fp d_lambda, int d_Nr, int d_Nc, long d_Ne, int* d_iN, int* d_iS, int* d_jE, int* d_jW,
                        fp* d_dN, fp* d_dS, fp* d_dE, fp* d_dW, fp d_q0sqr, fp* d_c, fp* d_I) {
    (void)d_lambda;
    (void)d_Nc;
    #pragma omp parallel for schedule(static)
    for (long ei = 0; ei < d_Ne; ei++) {
        int row = (int)((ei + 1) % d_Nr - 1);
        int col = (int)((ei + 1) / d_Nr + 1 - 1);
        if (((ei + 1) % d_Nr) == 0) {
            row = d_Nr - 1;
            col = col - 1;
        }

        fp d_Jc = d_I[ei];

        fp d_dN_loc = d_I[d_iN[row] + d_Nr * col] - d_Jc;
        fp d_dS_loc = d_I[d_iS[row] + d_Nr * col] - d_Jc;
        fp d_dW_loc = d_I[row + d_Nr * d_jW[col]] - d_Jc;
        fp d_dE_loc = d_I[row + d_Nr * d_jE[col]] - d_Jc;

        fp d_G2 = (d_dN_loc * d_dN_loc + d_dS_loc * d_dS_loc + d_dW_loc * d_dW_loc + d_dE_loc * d_dE_loc) / (d_Jc * d_Jc);
        fp d_L = (d_dN_loc + d_dS_loc + d_dW_loc + d_dE_loc) / d_Jc;

        fp d_num = (0.5f * d_G2) - ((1.0f / 16.0f) * (d_L * d_L));
        fp d_den = 1.0f + (0.25f * d_L);
        fp d_qsqr = d_num / (d_den * d_den);

        d_den = (d_qsqr - d_q0sqr) / (d_q0sqr * (1.0f + d_q0sqr));
        fp d_c_loc = 1.0f / (1.0f + d_den);

        if (d_c_loc < 0.0f) {
            d_c_loc = 0.0f;
        } else if (d_c_loc > 1.0f) {
            d_c_loc = 1.0f;
        }

        d_dN[ei] = d_dN_loc;
        d_dS[ei] = d_dS_loc;
        d_dW[ei] = d_dW_loc;
        d_dE[ei] = d_dE_loc;
        d_c[ei] = d_c_loc;
    }
}

static void srad2_kernel(fp d_lambda, int d_Nr, int d_Nc, long d_Ne, int* d_iN, int* d_iS, int* d_jE, int* d_jW,
                         fp* d_dN, fp* d_dS, fp* d_dE, fp* d_dW, fp* d_c, fp* d_I) {
    (void)d_Nc;
    (void)d_iN;
    (void)d_jW;
    #pragma omp parallel for schedule(static)
    for (long ei = 0; ei < d_Ne; ei++) {
        int row = (int)((ei + 1) % d_Nr - 1);
        int col = (int)((ei + 1) / d_Nr + 1 - 1);
        if (((ei + 1) % d_Nr) == 0) {
            row = d_Nr - 1;
            col = col - 1;
        }

        fp d_cN = d_c[ei];
        fp d_cS = d_c[d_iS[row] + d_Nr * col];
        fp d_cW = d_c[ei];
        fp d_cE = d_c[row + d_Nr * d_jE[col]];

        fp d_D = d_cN * d_dN[ei] + d_cS * d_dS[ei] + d_cW * d_dW[ei] + d_cE * d_dE[ei];
        d_I[ei] = d_I[ei] + 0.25f * d_lambda * d_D;
    }
}

static void compress_kernel(long d_Ne, fp* d_I) {
    #pragma omp parallel for schedule(static)
    for (long ei = 0; ei < d_Ne; ei++) {
        d_I[ei] = logf(d_I[ei]) * 255.0f;
    }
}

static void kernel_gpu_opencl_wrapper(fp* image, int Nr, int Nc, long Ne, int niter, fp lambda, long NeROI,
                                      int* iN, int* iS, int* jE, int* jW, int iter, int mem_size_i, int mem_size_j) {
    (void)iter;
    (void)mem_size_i;
    (void)mem_size_j;

    printf("Platform: OpenMP\n");
    printf("Device: CPU\n");
    printf("-----OpenCL Compiler Output-----\n");
    printf("--------------------------------\n");

    int blocks_x;
    int mem_size = (int)(sizeof(fp) * Ne);

    fp* d_I = (fp*)malloc(mem_size);
    int* d_iN = (int*)malloc(sizeof(int) * Nr);
    int* d_iS = (int*)malloc(sizeof(int) * Nr);
    int* d_jE = (int*)malloc(sizeof(int) * Nc);
    int* d_jW = (int*)malloc(sizeof(int) * Nc);
    fp* d_dN = (fp*)malloc(mem_size);
    fp* d_dS = (fp*)malloc(mem_size);
    fp* d_dW = (fp*)malloc(mem_size);
    fp* d_dE = (fp*)malloc(mem_size);
    fp* d_c = (fp*)malloc(mem_size);
    fp* d_sums = (fp*)malloc(mem_size);
    fp* d_sums2 = (fp*)malloc(mem_size);

    memcpy(d_I, image, mem_size);
    memcpy(d_iN, iN, sizeof(int) * Nr);
    memcpy(d_iS, iS, sizeof(int) * Nr);
    memcpy(d_jE, jE, sizeof(int) * Nc);
    memcpy(d_jW, jW, sizeof(int) * Nc);

    blocks_x = (int)(Ne / NUMBER_THREADS);
    if (Ne % NUMBER_THREADS != 0) {
        blocks_x = blocks_x + 1;
    }
    int blocks_work_size = blocks_x;

    printf("max # of workgroups = %d, # of threads/workgroup = %d (ensure that device can handle)\n",
           blocks_work_size, NUMBER_THREADS);

    extract_kernel(Ne, d_I);

    int blocks2_work_size;
    long no;
    int mul;
    fp total;
    fp total2;
    fp meanROI;
    fp meanROI2;
    fp varROI;
    fp q0sqr;

    printf("Iterations Progress: hidden");
    for (iter = 0; iter < niter; iter++) {
        fflush(NULL);

        prepare_kernel(Ne, d_I, d_sums, d_sums2);

        blocks2_work_size = blocks_work_size;
        no = Ne;
        mul = 1;

        while (blocks2_work_size != 0) {
            reduce_kernel(Ne, no, mul, d_sums, d_sums2, blocks2_work_size);

            no = blocks2_work_size;
            if (blocks2_work_size == 1) {
                blocks2_work_size = 0;
            } else {
                mul = mul * NUMBER_THREADS;
                blocks_x = blocks2_work_size / NUMBER_THREADS;
                if (blocks2_work_size % NUMBER_THREADS != 0) {
                    blocks_x = blocks_x + 1;
                }
                blocks2_work_size = blocks_x;
            }
        }

        total = d_sums[0];
        total2 = d_sums2[0];

        meanROI = total / (fp)(NeROI);
        meanROI2 = meanROI * meanROI;
        varROI = (total2 / (fp)(NeROI)) - meanROI2;
        q0sqr = varROI / meanROI2;

        srad_kernel(lambda, Nr, Nc, Ne, d_iN, d_iS, d_jE, d_jW, d_dN, d_dS, d_dE, d_dW, q0sqr, d_c, d_I);
        srad2_kernel(lambda, Nr, Nc, Ne, d_iN, d_iS, d_jE, d_jW, d_dN, d_dS, d_dE, d_dW, d_c, d_I);
    }
    printf("\n");

    compress_kernel(Ne, d_I);

    memcpy(image, d_I, mem_size);

    free(d_I);
    free(d_c);
    free(d_iN);
    free(d_iS);
    free(d_jE);
    free(d_jW);
    free(d_dN);
    free(d_dS);
    free(d_dE);
    free(d_dW);
    free(d_sums);
    free(d_sums2);
}

int main(int argc, char* argv[]) {
