    }
    for (j = 0; Nc > j; j++) {
        jW[j] = (int)j - 1;
        jE[j] = (int)j + 1;
    }

    iN[0] = 0;
    iS[Nr - 1] = Nr - 1;
    jW[0] = 0;
    jE[Nc - 1] = Nc - 1;

    kernel_gpu_opencl_wrapper(image,
