static void extract_kernel(long d_Ne, fp* d_I) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        d_I[ei] = exp(d_I[ei] / 255.0f);
    }
}

static void prepare_kernel(long d_Ne, fp* d_I, fp* d_sums, fp* d_sums2) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        d_sums[ei] = d_I[ei];
        d_sums2[ei] = d_I[ei] * d_I[ei];
    }
}

static void reduce_kernel(long d_Ne, long d_no, int d_mul, fp* d_sums, fp* d_sums2, int gridDim) {
    (void)d_Ne;
    #pragma omp parallel for
    for (int bx = 0; bx < gridDim; bx++) {
        int nf = NUMBER_THREADS - (gridDim * NUMBER_THREADS - (int)d_no);
        int df = 0;

        fp d_psum[NUMBER_THREADS];
        fp d_psum2[NUMBER_THREADS];

        for (int tx = 0; tx < NUMBER_THREADS; tx++) {
            long ei = (long)bx * NUMBER_THREADS + tx;
            if (d_no > ei) {
                d_psum[tx] = d_sums[ei * d_mul];
                d_psum2[tx] = d_sums2[ei * d_mul];
            } else {
                d_psum[tx] = 0.0f;
                d_psum2[tx] = 0.0f;
            }
        }

        if (nf == NUMBER_THREADS) {
            for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                for (int tx = 0; tx < NUMBER_THREADS; tx++) {
                    if (0 == (tx + 1) % i) {
                        d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                        d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                    }
                }
            }
            d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[NUMBER_THREADS - 1];
            d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[NUMBER_THREADS - 1];
        } else {
            if (bx != (gridDim - 1)) {
                for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                    for (int tx = 0; tx < NUMBER_THREADS; tx++) {
                        if (0 == (tx + 1) % i) {
                            d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                            d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                        }
                    }
                }
                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[NUMBER_THREADS - 1];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[NUMBER_THREADS - 1];
            } else {
                for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                    if (i <= nf) {
                        df = i;
                    }
                }

                for (int i = 2; df >= i; i = 2 * i) {
                    for (int tx = 0; tx < NUMBER_THREADS; tx++) {
                        if (0 == (tx + 1) % i && df > tx) {
                            d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                            d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                        }
                    }
                }

                int tx = df - 1;
                if (tx >= 0) {
                    for (int i = (bx * NUMBER_THREADS) + df; i < (bx * NUMBER_THREADS) + nf; i++) {
                        d_psum[tx] = d_psum[tx] + d_sums[i];
                        d_psum2[tx] = d_psum2[tx] + d_sums2[i];
                    }

                    d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                    d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
                }
            }
        }
    }
}

static void srad_kernel(
    fp d_lambda, int d_Nr, int d_Nc, long d_Ne, int* d_iN, int* d_iS, int* d_jE, int* d_jW,
    fp* d_dN, fp* d_dS, fp* d_dE, fp* d_dW, fp d_q0sqr, fp* d_c, fp* d_I) {
    (void)d_lambda;
    (void)d_Nc;
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        int row = (int)((ei + 1) % d_Nr - 1);
        int col = (int)((ei + 1) / d_Nr + 1 - 1);
        if (0 == (ei + 1) % d_Nr) {
            row = d_Nr - 1;
            col -= 1;
        }

        fp d_Jc = d_I[ei];

        fp d_dN_loc = d_I[d_iN[row] + d_Nr * col] - d_Jc;
        fp d_dS_loc = d_I[d_iS[row] + d_Nr * col] - d_Jc;
        fp d_dW_loc = d_I[row + d_Nr * d_jW[col]] - d_Jc;
        fp d_dE_loc = d_I[row + d_Nr * d_jE[col]] - d_Jc;

        fp d_G2 = (d_dN_loc * d_dN_loc + d_dS_loc * d_dS_loc + d_dW_loc * d_dW_loc + d_dE_loc * d_dE_loc) / (d_Jc * d_Jc);
        fp d_L = (d_dN_loc + d_dS_loc + d_dW_loc + d_dE_loc) / d_Jc;

        fp d_num = (0.5f * d_G2) - ((1.0f / 16.0f) * (d_L * d_L));
        fp d_den = 1.0f + (0.25f * d_L);
        fp d_qsqr = d_num / (d_den * d_den);

        d_den = (d_qsqr - d_q0sqr) / (d_q0sqr * (1.0f + d_q0sqr));
        fp d_c_loc = 1.0f / (1.0f + d_den);

        if (d_c_loc < 0.0f) {
            d_c_loc = 0.0f;
        } else if (d_c_loc > 1.0f) {
            d_c_loc = 1.0f;
        }

        d_dN[ei] = d_dN_loc;
        d_dS[ei] = d_dS_loc;
        d_dW[ei] = d_dW_loc;
        d_dE[ei] = d_dE_loc;
        d_c[ei] = d_c_loc;
    }
}

static void srad2_kernel(
    fp d_lambda, int d_Nr, int d_Nc, long d_Ne, int* d_iN, int* d_iS, int* d_jE, int* d_jW,
    fp* d_dN, fp* d_dS, fp* d_dE, fp* d_dW, fp* d_c, fp* d_I) {
    (void)d_Nc;
    (void)d_iN;
    (void)d_jW;
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        int row = (int)((ei + 1) % d_Nr - 1);
        int col = (int)((ei + 1) / d_Nr + 1 - 1);
        if (0 == (ei + 1) % d_Nr) {
            row = d_Nr - 1;
            col -= 1;
        }

        fp d_cN = d_c[ei];
        fp d_cS = d_c[d_iS[row] + d_Nr * col];
        fp d_cW = d_c[ei];
        fp d_cE = d_c[row + d_Nr * d_jE[col]];

        fp d_D = d_cN * d_dN[ei] + d_cS * d_dS[ei] + d_cW * d_dW[ei] + d_cE * d_dE[ei];
        d_I[ei] = d_I[ei] + 0.25f * d_lambda * d_D;
    }
}

static void compress_kernel(long d_Ne, fp* d_I) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        d_I[ei] = log(d_I[ei]) * 255.0f;
    }
}

static void kernel_gpu_opencl_wrapper(fp* image, int Nr, int Nc, long Ne, int niter, fp lambda, long NeROI,
                                      int* iN, int* iS, int* jE, int* jW, int iter, int mem_size_i, int mem_size_j) {
    (void)iter;
    (void)mem_size_i;
    (void)mem_size_j;

    printf("Platform: OpenMP\n");
    printf("Device: CPU\n");
    printf("-----OpenCL Compiler Output-----\n");
    printf("--------------------------------\n");

    int mem_size = (int)(sizeof(fp) * Ne);

    fp* d_I = (fp*)malloc(mem_size);
    int* d_iN = (int*)malloc(sizeof(int) * Nr);
    int* d_iS = (int*)malloc(sizeof(int) * Nr);
    int* d_jE = (int*)malloc(sizeof(int) * Nc);
    int* d_jW = (int*)malloc(sizeof(int) * Nc);
    fp* d_dN = (fp*)malloc(mem_size);
    fp* d_dS = (fp*)malloc(mem_size);
    fp* d_dW = (fp*)malloc(mem_size);
    fp* d_dE = (fp*)malloc(mem_size);
    fp* d_c = (fp*)malloc(mem_size);
    fp* d_sums = (fp*)malloc(mem_size);
    fp* d_sums2 = (fp*)malloc(mem_size);

    memcpy(d_I, image, mem_size);
    memcpy(d_iN, iN, sizeof(int) * Nr);
    memcpy(d_iS, iS, sizeof(int) * Nr);
    memcpy(d_jE, jE, sizeof(int) * Nc);
    memcpy(d_jW, jW, sizeof(int) * Nc);

    int blocks_x;
    int local_work_size = NUMBER_THREADS;
    blocks_x = (int)(Ne / local_work_size);
    if (0 != Ne % local_work_size) {
        blocks_x += 1;
    }
    int blocks_work_size = blocks_x;
    long global_work_size = (long)blocks_work_size * local_work_size;

    printf("max # of workgroups = %d, # of threads/workgroup = %d (ensure that device can handle)\n",
           (int)(global_work_size / local_work_size), local_work_size);

    extract_kernel(Ne, d_I);

    int blocks2_work_size;
    long no;
    int mul;
    fp total;
    fp total2;
    fp meanROI;
    fp meanROI2;
    fp varROI;
    fp q0sqr;

