    free(d_I);
    free(d_c);
    free(d_iN);
    free(d_iS);
    free(d_jE);
    free(d_jW);
    free(d_dN);
    free(d_dS);
    free(d_dE);
    free(d_dW);
    free(d_sums);
    free(d_sums2);
}

