RSComplex c_mul(RSComplex A, RSComplex B)
{
	double a = A.r;
	double b = A.i;
	double c = B.r;
	double d = B.i;
	RSComplex C;
	C.r = (a * c) - (b * d);
	C.i = (a * d) + (b * c);
	return C;
}

RSComplex c_div(RSComplex A, RSComplex B)
{
	double a = A.r;
	double b = A.i;
	double c = B.r;
	double d = B.i;
	RSComplex C;
	double denom = c * c + d * d;
	C.r = ((a * c) + (b * d)) / denom;
	C.i = ((b * c) - (a * d)) / denom;
	return C;
}

