		uint64_t seed = STARTING_SEED;
		seed = fast_forward_LCG(seed, 2ULL * (uint64_t)i);

		double p_energy = LCG_random_double(&seed);
		int mat = pick_mat(&seed);

		double macro_xs_vector[4] = {0.0, 0.0, 0.0, 0.0};
		calculate_macro_xs(macro_xs_vector, mat, p_energy, input, data);

		double max = -DBL_MAX;
		int max_idx = 0;
		for (int j = 0; j < 4; j++)
		{
			if (macro_xs_vector[j] > max)
			{
				max = macro_xs_vector[j];
				max_idx = j;
			}
		}
		verification_array[i] = max_idx + 1;
	}

	printf("Reducing verification value...\n");

	unsigned long long verification = 0ULL;
	#pragma omp parallel for reduction(+:verification) schedule(static)
	for (int l = 0; l < input.lookups; l++)
		verification += (unsigned long long)verification_array[l];

	double stop = get_time();
	printf("Simulation + Verification Reduction Runtime: %.3lf seconds\n", stop - start);

	*vhash_result = (unsigned long)verification;
	free(verification_array);
}

void run_event_based_simulation_optimization_1(Input in, SimulationData SD, unsigned long * vhash_result)
{
	run_event_based_simulation(in, SD, vhash_result);
}
